from __future__ import annotations
import csv,json,shutil
import numpy as np
from collections import Counter
from dataclasses import dataclass
from pathlib import Path
from app6.stage1.utils import atomic_json,sha256_file
SCHEMA='deeputin-stage3-v1.4'
@dataclass(frozen=True)
class Stage3Config: analysis_root:Path;output_dir:Path;overwrite:bool=False

def rows(path):
 with path.open(newline='',encoding='utf-8') as f:return list(csv.DictReader(f))
def num(v,default=0.0):
 try:return float(v)
 except:return default
class Stage3Engine:
 def __init__(self,cfg):self.cfg=cfg
 def run(self):
  o=self.cfg.output_dir
  if o.exists() and any(o.iterdir()) and not self.cfg.overwrite:raise FileExistsError(f'output exists: {o}')
  if o.exists() and self.cfg.overwrite:shutil.rmtree(o)
  o.mkdir(parents=True)
  a=self.cfg.analysis_root;manifest=json.loads((a/'analysis_manifest.json').read_text());pairs=rows(a/'pair_metrics.csv');zones=rows(a/'zone_metrics.csv');changes=json.loads((a/'change_points.json').read_text()).get('change_points',[]);leads=json.loads((a/'lead_registry.json').read_text()) if (a/'lead_registry.json').is_file() else {'status':'not_provided','dates':{},'coverage':[]};metric_catalog=json.loads((a/'metric_catalog.json').read_text()) if (a/'metric_catalog.json').is_file() else {'schema':'missing','registry_size':0,'metrics':[]}
  adjacent=[r for r in pairs if r.get('pair_type')=='adjacent'];statuses=Counter(r.get('status','unknown') for r in pairs);poses=Counter(r.get('pose_bin','unknown') for r in adjacent);lead_pairs=[r for r in adjacent if str(r.get('lead_overlap','')).lower() in ('true','1')]
  timelines={}
  for pose in sorted(poses):timelines[pose]=sorted([{'date':r.get('date_b'),'photo_a':r.get('photo_a'),'photo_b':r.get('photo_b'),'status':r.get('status'),'p95_point_z':num(r.get('p95_point_z')),'coherence':num(r.get('coherent_motion_fraction')),'expression_influence':num(r.get('expression_influence')),'days_delta':num(r.get('days_delta',-1))} for r in adjacent if r.get('pose_bin')==pose],key=lambda x:(x['date'] or ''))
  ordered=sorted(adjacent,key=lambda r:num(r.get('p95_point_z')),reverse=True);selected=[];seen=set()
  for r in ordered:
   if len(selected)>=40:break
   if r.get('pair_id') in seen:continue
   selected.append(r);seen.add(r.get('pair_id'))
  noise=np.load(a/'point_noise_model.npz',allow_pickle=False) if (a/'point_noise_model.npz').is_file() else None;motion_maps=[]
  for r in selected:
   mf=a/r.get('motion_file','')
   if not mf.is_file():continue
   with np.load(mf,allow_pickle=False) as z:
    zz=z['ldm134_point_z'];vec=z['ldm134_vectors'];mag=z['ldm134_magnitude'];sig=z['ldm134_significant'].astype(bool)
    key=f"{r.get('pose_bin')}__ldm134__template";template=noise[key] if noise is not None and key in noise else np.column_stack((np.arange(134),np.zeros(134),np.zeros(134)))
    pts=[{'i':i,'x':float(template[i,0]),'y':float(template[i,1]),'z':float(zz[i]) if np.isfinite(zz[i]) else None,'dx':float(vec[i,0]) if np.isfinite(vec[i,0]) else None,'dy':float(vec[i,1]) if np.isfinite(vec[i,1]) else None,'magnitude':float(mag[i]) if np.isfinite(mag[i]) else None,'significant':bool(sig[i])} for i in range(134)]
    motion_maps.append({'pair_id':r.get('pair_id'),'label':f"{r.get('date_b')} · {r.get('pose_bin')} · {r.get('photo_a')} → {r.get('photo_b')}",'status':r.get('status'),'points':pts})
  dates=sorted({r.get('date_b') for r in adjacent if r.get('date_b')});poor=sum(1 for r in adjacent if num(r.get('matched_calibration_sets'))<7);bio=sum(1 for r in adjacent if str(r.get('biological_rate_status','')).startswith(('same_day','biologically','persistent_biologically')))
  uv_zones=[]
  uv_path=a/'uv_geometry_zone_metrics.csv'
  if uv_path.is_file():
   try:uv_zones=rows(uv_path)
   except Exception:uv_zones=[]
  uv_available=sum(1 for r in pairs if str(r.get('uv_geometry_status','')) in ('measured','native_surface_available'))
  uv_max_delta=max((num(r.get('uv_max_ridge_density_delta',0)) for r in pairs if r.get('uv_geometry_status')=='measured'),default=0)
  narrative=[f"Исследование охватывает {manifest.get('main_record_count',0)} фотографий"+(f" за период {dates[0]} — {dates[-1]}" if dates else '')+f". Хронология разделена на {len(poses)} независимых ракурсных ряда.",f"Для каждой пары движение 134 точек сопоставлено с same-person noise семи калибровочных наборов. Полное покрытие семью наборами отсутствовало у {poor} соседних сравнений.",f"Архив прежних зацепок содержит {leads.get('date_count',0)} дат и {leads.get('metric_count',0)} названий метрик. В новой хронологии напрямую пересекаются {len(lead_pairs)} соседних пар. Старые выводы используются только как цели перепроверки.",f"Помимо движения точек проверяются 13 локальных семейств shape. Отдельно подсчитывается биологически маловероятный темп: скачок нормируется на количество дней между кадрами и помечается только как candidate, а не как доказанный факт.",f"UV/native-surface adapter: {uv_available} pairs with native_surface_available/measured; Frangi+skan ridge metrics are NOT claimed unless uv_wrinkle_metrics_status=measured (adapter currently often not_measured). UV bake remains viz/morph only.",f"Найдено {bio} соседних пар с аномальным темпом изменения и {len(changes)} сильных change-point candidates. Мимика контролируется через identity-only landmarks и alpha_exp.","Ни один статус сам по себе не доказывает подмену личности, маску, операцию или причину изменения. Отчёт отделяет наблюдаемое движение точек от интерпретации."]
  data={'schema_version':SCHEMA,'analysis_manifest':manifest,'summary':{'pair_count':len(pairs),'zone_count':len(zones),'change_count':len(changes),'lead_pair_count':len(lead_pairs),'uv_available_pairs':uv_available,'uv_zone_count':len(uv_zones),'status_counts':statuses,'pose_counts':poses},'narrative':narrative,'timelines':timelines,'motion_maps':motion_maps,'pairs':pairs,'lead_pairs':lead_pairs,'lead_registry':leads,'metric_catalog':metric_catalog,'zones':zones,'uv_zones':uv_zones,'change_points':changes,'methodology':{'stage1':'Single 3DDFA inference with validated immutable extraction.','stage2':'Chronology is isolated by pose bin; every landmark and every local descriptor family has a same-person calibration noise distribution.','uv_geometry':'Native-surface adapter and/or measured UV metrics only when status=measured; do not claim Frangi+skan unless the producer emitted measured wrinkle metrics.','interpretation':'Prior leads define coverage targets, never ground truth. Statuses do not establish identity replacement, masks, surgery, or medical facts.'}}
  atomic_json(o/'report_data.json',data);(o/'index.html').write_text(self._html(data),encoding='utf-8')
  validation={'schema_version':'stage3-validation-v1','status':'complete','errors':[],'analysis_manifest_sha256':sha256_file(a/'analysis_manifest.json'),'files':['index.html','report_data.json']};atomic_json(o/'report_validation.json',validation);return validation
 def _html(self,data):
  payload=json.dumps(data,ensure_ascii=False).replace('</','<\\/')
  return TEMPLATE.replace('__DATA__',payload)
TEMPLATE=r'''<!doctype html><html lang="ru"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>DEEPUTIN · calibrated chronology</title><style>:root{--bg:#fff;--surface:#f9f8f7;--surface2:#f0efed;--text:#2c2c2b;--muted:#706d68;--border:#e6e5e3;--blue:#2783de;--blueSoft:#e5f2fc;--green:#367f59;--greenSoft:#e8f1ec;--orange:#a75e22;--orangeSoft:#fbebde;--red:#b9463c;--redSoft:#fce9e7}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font:16px/1.5 -apple-system,BlinkMacSystemFont,"Segoe UI",Arial,sans-serif}.shell{max-width:1120px;margin:auto;padding:40px 32px 72px}.eyebrow{color:var(--blue);font-weight:700;letter-spacing:.08em;text-transform:uppercase;font-size:13px}h1{font-size:clamp(36px,6vw,64px);line-height:1.02;letter-spacing:-.045em;margin:10px 0 18px;max-width:850px}h2{font-size:28px;letter-spacing:-.025em;margin:0 0 18px}p{max-width:760px}.lead{font-size:19px;color:var(--muted)}.notice{border-left:3px solid var(--blue);padding:14px 18px;background:var(--blueSoft);margin:28px 0 40px;max-width:850px}.grid{display:grid;grid-template-columns:repeat(4,1fr);gap:12px}.card{border:1px solid var(--border);border-radius:10px;padding:20px;background:#fff}.metric{font-size:32px;font-weight:750;letter-spacing:-.04em}.label{font-size:14px;color:var(--muted)}section{margin-top:56px}.two{display:grid;grid-template-columns:1fr 1fr;gap:20px}.panel{background:var(--surface);border:1px solid var(--border);border-radius:12px;padding:24px}.bar{display:grid;grid-template-columns:minmax(190px,auto) 1fr 32px;gap:10px;align-items:center;margin:10px 0;font-size:14px}.bar>span{overflow-wrap:anywhere}.track{height:8px;background:var(--surface2);border-radius:8px;overflow:hidden}.fill{height:100%;background:var(--blue)}.toolbar{display:flex;gap:12px;margin-bottom:14px}.toolbar input,.toolbar select{min-height:44px;border:1px solid var(--border);border-radius:8px;padding:8px 12px;background:#fff;color:var(--text)}.toolbar input{flex:1}.tableWrap{overflow:auto;border:1px solid var(--border);border-radius:10px}table{border-collapse:collapse;width:100%;min-width:860px;font-size:14px}th,td{text-align:left;padding:12px 14px;border-bottom:1px solid var(--border);white-space:nowrap}th{position:sticky;top:0;background:var(--surface);color:var(--muted);font-weight:650}tr:last-child td{border-bottom:0}.tag{display:inline-block;padding:3px 8px;border-radius:6px;font-size:12px;font-weight:700;background:var(--surface2);max-width:100%;overflow-wrap:anywhere;white-space:normal}.within_calibration_noise,.within_reconstruction_noise,.within_expected_pace{background:var(--greenSoft);color:var(--green)}.persistent_geometric_change,.same_day_structural_conflict,.biologically_improbable_rate_candidate,.persistent_biologically_improbable_change{background:var(--redSoft);color:var(--red)}.expression_dominated,.descriptor_uncertain,.scattered_or_uncertain{background:var(--orangeSoft);color:var(--orange)}.empty{color:var(--muted);padding:24px}.method{counter-reset:s}.step{display:grid;grid-template-columns:36px 1fr;gap:14px;margin:18px 0}.step:before{counter-increment:s;content:counter(s);width:32px;height:32px;display:grid;place-items:center;border:1px solid var(--border);border-radius:50%;font-weight:700}.small{font-size:13px;color:var(--muted)}.narrative{display:grid;gap:12px}.finding{padding:16px 18px;border-left:3px solid var(--border);background:var(--surface);border-radius:0 8px 8px 0}.chart{width:100%;min-height:260px}.chart svg,.motionSvg{width:100%;height:auto;display:block}.legend{display:flex;gap:18px;flex-wrap:wrap;color:var(--muted);font-size:13px}.dot{width:9px;height:9px;display:inline-block;border-radius:50%;margin-right:5px}.motionControls{display:flex;gap:12px;align-items:center;margin-bottom:16px;flex-wrap:wrap}.motionControls select{min-height:44px;max-width:100%;min-width:0;flex:1 1 240px;border:1px solid var(--border);border-radius:8px;padding:8px 12px;background:var(--bg);color:var(--text)}footer{margin-top:64px;padding-top:24px;border-top:1px solid var(--border);color:var(--muted);font-size:13px}@media(max-width:760px){.shell{padding:28px 18px 56px}.grid{grid-template-columns:1fr 1fr}.two{grid-template-columns:1fr}.toolbar{flex-direction:column}.bar{grid-template-columns:minmax(140px,auto) 1fr 28px}h1{font-size:40px}}@media(prefers-color-scheme:dark){:root{--bg:#191919;--surface:#202020;--surface2:#383836;--text:#fff;--muted:rgba(255,255,255,.65);--border:rgba(255,255,255,.2);--blue:#5e9fe8;--blueSoft:#202f3d;--green:#72bc8f;--greenSoft:#203028;--orange:#de9255;--orangeSoft:#39291e;--red:#e97366;--redSoft:#3a2220}.card,.toolbar input,.toolbar select{background:var(--surface)}th{background:#252525}}</style></head><body><main class="shell"><div class="eyebrow">DEEPUTIN / Stage 3</div><h1>Калиброванная хронология реконструкций</h1><p class="lead">Отчёт объединяет валидированные данные этапа 1, сравнения внутри одинаковых ракурсов, скорость изменений по дням и семь независимых оценок шума модели.</p><div class="notice"><strong>Граница интерпретации.</strong> Отчёт показывает величину, темп и устойчивость изменений относительно calibration noise. Он не доказывает подмену личности, использование маски, операцию или медицинский факт.</div><div class="grid" id="cards"></div><section><h2>Расследовательская сводка</h2><div class="narrative" id="narrative"></div></section><section><h2>Перепроверка архива зацепок</h2><p class="lead">Старые результаты используются как карта покрытия. Они не изменяют calibration thresholds и не считаются заранее истинными.</p><div class="grid"><div class="card"><div class="metric" id="leadDates"></div><div class="label">дат в реестре</div></div><div class="card"><div class="metric" id="leadMetrics"></div><div class="label">старых метрик</div></div><div class="card"><div class="metric" id="leadPairs"></div><div class="label">пересечений в новой хронологии</div></div><div class="card"><div class="metric">13</div><div class="label">локальных семейств shape</div></div></div><div id="leadTable" style="margin-top:18px"></div></section><section><h2>Хронология движения точек</h2><p class="lead">Каждая линия — отдельный ракурс. Высота показывает превышение движения точек над их собственным same-person reconstruction noise.</p><div class="panel chart" id="timeline"></div></section><section><h2>Карта движения LDM134</h2><p class="lead">Показаны все одновременно видимые точки выбранной пары. Красные точки образуют согласованные группы, движение которых выше калибровочного шума.</p><div class="panel"><div class="motionControls"><select id="motionSelect" aria-label="Пара для карты движения"></select><span class="tag" id="motionStatus"></span></div><div id="motionMap"></div><div class="legend"><span><i class="dot" style="background:#b9463c"></i>выше шума</span><span><i class="dot" style="background:#2783de"></i>в пределах шума</span><span>стрелка — направление движения после alignment</span></div></div></section><section><div class="two"><div class="panel"><h2>Ракурсы</h2><div id="poses"></div></div><div class="panel"><h2>Статусы</h2><div id="statuses"></div></div></div></section><section><h2>Кандидаты изменений</h2><div id="changes"></div></section><section><h2>UV-геометрия кожи</h2><p class="lead">UV/native-surface channel when measured. Do not treat adapter-only rows as Frangi+skan evidence. Not same-person calibrated — technical observation only.</p><div id="uvSection"></div></section><section><h2>Все сравнения</h2><div class="toolbar"><input id="search" aria-label="Поиск" placeholder="Фото, дата или ракурс"><select id="statusFilter" aria-label="Статус"><option value="">Все статусы</option></select></div><div class="tableWrap"><table><thead><tr><th>Дата B</th><th>Ракурс</th><th>Тип</th><th>Фото A → B</th><th>Дни</th><th>Точек выше шума</th><th>P95 point z</th><th>Локальные признаки</th><th>Темп</th><th>Статус</th></tr></thead><tbody id="pairs"></tbody></table></div></section><section><div class="panel method"><h2>Как читать результат</h2><div class="step"><div><strong>Однородный ракурс</strong><div class="small">Хронология разделена по pose bin. Разные bins не смешиваются в основной вывод.</div></div></div><div class="step"><div><strong>Общая видимость</strong><div class="small">Используются только landmarks, видимые одновременно на обеих фотографиях.</div></div></div><div class="step"><div><strong>Семь null-оценок</strong><div class="small">Каждая пара сопоставляется с кадрами семи same-person calibration datasets.</div></div></div><div class="step"><div><strong>Темп изменения</strong><div class="small">Резкий согласованный скачок за слишком короткий промежуток времени получает отдельный chronology-rate статус, но остаётся только candidate.</div></div></div></div></section><footer id="footer"></footer></main><script>const D=__DATA__;const $=s=>document.querySelector(s);const esc=s=>String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));const n=v=>Number(v||0);$('#cards').innerHTML=[['Фотографии',D.analysis_manifest.main_record_count],['Сравнения',D.summary.pair_count],['Кандидаты',D.summary.change_count],['Calibration',D.analysis_manifest.calibration_dataset_count]].map(x=>`<div class="card"><div class="metric">${x[1]}</div><div class="label">${x[0]}</div></div>`).join('');$('#leadDates').textContent=D.lead_registry.date_count||0;$('#leadMetrics').textContent=D.lead_registry.metric_count||0;$('#leadPairs').textContent=D.summary.lead_pair_count||0;$('#leadTable').innerHTML=D.lead_pairs.length?`<div class="tableWrap"><table><thead><tr><th>Дата</th><th>Ракурс</th><th>Приоритет</th><th>Зоны архива</th><th>Новые descriptor families</th><th>Новый статус</th></tr></thead><tbody>${D.lead_pairs.map(x=>`<tr><td>${esc(x.date_b)}</td><td>${esc(x.pose_bin)}</td><td>${esc(x.lead_priority)}</td><td>${esc(x.lead_regions||'—')}</td><td>${esc(x.descriptor_top_families||'в пределах noise')}</td><td><span class="tag ${esc(x.status)}">${esc(x.status)}</span></td></tr>`).join('')}</tbody></table></div>`:'<div class="panel empty">В текущем наборе нет прямых пересечений со старыми датами.</div>';$('#narrative').innerHTML=D.narrative.map((x,i)=>`<div class="finding"><strong>${['Масштаб','Калибровка','Архив зацепок','Shape families','UV-геометрия кожи','Контроль мимики','Граница вывода'][i]||'Факт'}</strong><div>${esc(x)}</div></div>`).join('');function timeline(){const colors=['#2783de','#b9463c','#367f59','#a75e22','#7857a5','#0b7d7b'];const blocks=Object.entries(D.timelines).map(([pose,rs],pi)=>{if(!rs.length)return '';const w=900,h=220,p=38,max=Math.max(4,...rs.map(x=>n(x.p95_point_z)));const pts=rs.map((x,i)=>[p+(w-2*p)*(rs.length===1?.5:i/(rs.length-1)),h-p-(h-2*p)*Math.min(n(x.p95_point_z),max)/max,x]);const line=pts.map(x=>`${x[0]},${x[1]}`).join(' ');return `<div style="margin-bottom:26px"><strong>${esc(pose)}</strong><svg viewBox="0 0 ${w} ${h}" role="img" aria-label="Хронология ${esc(pose)}"><line x1="${p}" y1="${h-p-(h-2*p)*3.5/max}" x2="${w-p}" y2="${h-p-(h-2*p)*3.5/max}" stroke="#a75e22" stroke-dasharray="6 5"/><polyline fill="none" stroke="${colors[pi%colors.length]}" stroke-width="3" points="${line}"/>${pts.map(q=>`<circle cx="${q[0]}" cy="${q[1]}" r="${q[2].status.includes('improbable')||q[2].status.includes('persistent')?7:5}" fill="${q[2].status.includes('improbable')||q[2].status.includes('persistent')?'#b9463c':colors[pi%colors.length]}"><title>${esc(q[2].date)} · p95 z ${n(q[2].p95_point_z).toFixed(2)} · days ${q[2].days_delta}</title></circle>`).join('')}<text x="${p}" y="${h-8}" fill="currentColor" opacity=".6">${esc(rs[0].date||'')}</text><text x="${w-p}" y="${h-8}" text-anchor="end" fill="currentColor" opacity=".6">${esc(rs.at(-1).date||'')}</text></svg></div>`}).join('');$('#timeline').innerHTML=blocks||'<div class="empty">Недостаточно соседних фотографий для временной линии.</div>'}timeline();function motion(){const s=$('#motionSelect');s.innerHTML=D.motion_maps.map((m,i)=>`<option value="${i}">${esc(m.label)}</option>`).join('');function draw(){const m=D.motion_maps[n(s.value)];if(!m){$('#motionMap').innerHTML='<div class="empty">Нет пригодных карт движения.</div>';return}$('#motionStatus').textContent=m.status;const pts=m.points.filter(p=>p.z!==null),xs=pts.map(p=>p.x),ys=pts.map(p=>p.y),xmin=Math.min(...xs),xmax=Math.max(...xs),ymin=Math.min(...ys),ymax=Math.max(...ys),w=900,h=520,pad=34,px=x=>pad+(x-xmin)/Math.max(xmax-xmin,1e-8)*(w-2*pad),py=y=>h-pad-(y-ymin)/Math.max(ymax-ymin,1e-8)*(h-2*pad),maxMag=Math.max(...pts.map(p=>n(p.magnitude)),1e-8),scale=22/maxMag;$('#motionMap').innerHTML=`<svg class="motionSvg" viewBox="0 0 ${w} ${h}" role="img" aria-label="Движение 134 точек">${pts.map(q=>`<line x1="${px(q.x)}" y1="${py(q.y)}" x2="${px(q.x)+n(q.dx)*scale}" y2="${py(q.y)-n(q.dy)*scale}" stroke="${q.significant?'#b9463c':'#2783de'}" stroke-opacity=".55"/><circle cx="${px(q.x)}" cy="${py(q.y)}" r="${q.significant?5:3}" fill="${q.significant?'#b9463c':'#2783de'}"><title>Point ${q.i} · z ${n(q.z).toFixed(2)} · magnitude ${n(q.magnitude).toFixed(5)}</title></circle>`).join('')}</svg>`}s.addEventListener('change',draw);draw()}motion();function bars(sel,obj){const max=Math.max(1,...Object.values(obj).map(n));$(sel).innerHTML=Object.entries(obj).sort((a,b)=>b[1]-a[1]).map(([k,v])=>`<div class="bar"><span>${esc(k)}</span><div class="track"><div class="fill" style="width:${100*n(v)/max}%"></div></div><b>${v}</b></div>`).join('')||'<div class="empty">Нет данных</div>'}bars('#poses',D.summary.pose_counts);bars('#statuses',D.summary.status_counts);$('#changes').innerHTML=D.change_points.length?`<div class="tableWrap"><table><thead><tr><th>Дата</th><th>Ракурс</th><th>Пара</th><th>Дни</th><th>P95 point z</th><th>Темп</th><th>Статус</th></tr></thead><tbody>${D.change_points.map(x=>`<tr><td>${esc(x.date)}</td><td>${esc(x.pose_bin)}</td><td>${esc(x.photo_a)} → ${esc(x.photo_b)}</td><td>${esc(x.days_delta)}</td><td>${n(x.p95_point_z).toFixed(2)}</td><td>${esc(x.biological_rate_status||'—')}</td><td><span class="tag ${esc(x.status)}">${esc(x.status)}</span></td></tr>`).join('')}</tbody></table></div>`:'<div class="panel empty">Кандидаты устойчивых изменений не обнаружены.</div>';if(D.uv_zones&&D.uv_zones.length){const uvByPair={};D.uv_zones.forEach(z=>{if(!uvByPair[z.pair_id])uvByPair[z.pair_id]=[];uvByPair[z.pair_id].push(z)});const uvRows=Object.entries(uvByPair).sort((a,b)=>{const ma=Math.max(...a[1].map(z=>n(z.ridge_density_delta||0)));const mb=Math.max(...b[1].map(z=>n(z.ridge_density_delta||0)));return mb-ma}).slice(0,30);$('#uvSection').innerHTML='<div class="tableWrap"><table><thead><tr><th>Пара</th><th>Зона</th><th>Ridge density Δ</th><th>Branch Δ</th><th>Length Δ</th><th>Ridge strength Δ</th></tr></thead><tbody>'+uvRows.flatMap(([pid,zones])=>zones.map(z=>'<tr><td>'+esc(z.pair_id)+'</td><td>'+esc(z.zone||'—')+'</td><td>'+n(z.ridge_density_delta).toFixed(4)+'</td><td>'+n(z.branch_count_delta).toFixed(1)+'</td><td>'+n(z.total_length_delta).toFixed(1)+'</td><td>'+n(z.ridge_strength_delta).toFixed(4)+'</td></tr>')).join('')+'</tbody></table></div>'}else{$('#uvSection').innerHTML='<div class="panel empty">UV-геометрия кожи не измерена или данных недостаточно.</div>'};const statuses=[...new Set(D.pairs.map(x=>x.status))].sort();$('#statusFilter').innerHTML+=""+statuses.map(x=>`<option>${esc(x)}</option>`).join('');function render(){const q=$('#search').value.toLowerCase(),sf=$('#statusFilter').value;const rs=D.pairs.filter(x=>(!sf||x.status===sf)&&JSON.stringify(x).toLowerCase().includes(q));$('#pairs').innerHTML=rs.map(x=>`<tr><td>${esc(x.date_b)}</td><td>${esc(x.pose_bin)}</td><td>${esc(x.pair_type)}</td><td>${esc(x.photo_a)} → ${esc(x.photo_b)}</td><td>${esc(x.days_delta)}</td><td>${(100*n(x.significant_point_fraction)).toFixed(1)}%</td><td>${n(x.p95_point_z).toFixed(2)}</td><td>${esc(x.descriptor_top_families||'—')}</td><td>${esc(x.biological_rate_status||'—')}</td><td><span class="tag ${esc(x.status)}">${esc(x.status)}</span></td></tr>`).join('')||'<tr><td colspan="10" class="empty">Ничего не найдено</td></tr>'}$('#search').addEventListener('input',render);$('#statusFilter').addEventListener('change',render);render();$('#footer').textContent=`Schema ${D.schema_version} · Stage 2 ${D.analysis_manifest.schema_version} · ${D.analysis_manifest.created_at_utc}`;</script></body></html>''' 
